#!/usr/bin/env python3
"""apply_otdesi.py — inject O.T. & Desi assets a1013 (full-art) + a1014 (battle) into assets/assets.json."""
import json,os,sys
root=os.path.dirname(os.path.abspath(__file__))
ap=os.path.join(root,"assets/assets.json")
if not os.path.exists(ap): sys.exit("[apply] assets/assets.json not found")
d=json.load(open(ap))
d.update({"a1013": "", "a1014": ""})
json.dump(d,open(ap,"w"))
print("[apply] wrote O.T. & Desi assets a1013-a1014")
